  5→package kotlinx.coroutines.internal
  6→
  7→import kotlinx.coroutines.*
  8→import java.lang.reflect.*
  9→import java.util.*
 10→import java.util.concurrent.locks.*
 11→import kotlin.concurrent.*
 12→
 13→private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
 14→private typealias Ctor = (Throwable) -> Throwable?
 15→
 16→private val ctorCache = try {
 17→    if (ANDROID_DETECTED) WeakMapCtorCache
 18→    else ClassValueCtorCache
 19→} catch (e: Throwable) {
 20→    // Fallback on Java 6 or exotic setups
 21→    WeakMapCtorCache
 22→}
 23→
 24→@Suppress("UNCHECKED_CAST")
 25→internal fun <E : Throwable> tryCopyException(exception: E): E? {
 26→    // Fast path for CopyableThrowable
 27→    if (exception is CopyableThrowable<*>) {
 28→        return runCatching { exception.createCopy() as E? }.getOrNull()
 29→    }
 30→    return ctorCache.get(exception.javaClass).invoke(exception) as E?
 31→}
 32→
 33→private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34→    val nullResult: Ctor = { null } // Pre-cache class
 35→    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36→    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37→    /*
 38→    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39→    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40→    */
 41→    val constructors = clz.constructors.sortedByDescending { it.parameterTypes.size }
 42→    for (constructor in constructors) {
 43→        val result = createSafeConstructor(constructor)
 44→        if (result != null) return result
 45→    }
 46→    return nullResult
 47→}
 48→
 49→private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
 50→    val p = constructor.parameterTypes
 51→    return when (p.size) {
 52→        2 -> when {
 53→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 54→                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 55→            else -> null
 56→        }
 57→        1 -> when (p[0]) {
 58→            Throwable::class.java ->
 59→                safeCtor { e -> constructor.newInstance(e) as Throwable }
 60→            String::class.java ->
 61→                safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 62→            else -> null
 63→        }
 64→        0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 65→        else -> null
 66→    }
 67→}
 68→
 69→private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
 70→    { e -> runCatching { block(e) }.getOrNull() }
 71→
 72→private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
 73→    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)
 74→
 75→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 76→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 77→    val totalFields = accumulator + fieldsCount
 78→    val superClass = superclass ?: return totalFields
 79→    return superClass.fieldsCount(totalFields)
 80→}
 81→
 82→internal abstract class CtorCache {
 83→    abstract fun get(key: Class<out Throwable>): Ctor
 84→}
 85→
 86→private object WeakMapCtorCache : CtorCache() {
 87→    private val cacheLock = ReentrantReadWriteLock()
 88→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
 89→
 90→    override fun get(key: Class<out Throwable>): Ctor {
 91→        cacheLock.read { exceptionCtors[key]?.let { return it } }
 92→        cacheLock.write {
 93→            exceptionCtors[key]?.let { return it }
 94→            return createConstructor(key).also { exceptionCtors[key] = it }
 95→        }
 96→    }
 97→}
 98→
 99→@IgnoreJreRequirement
100→private object ClassValueCtorCache : CtorCache() {
101→    private val cache = object : ClassValue<Ctor>() {
102→        override fun computeValue(type: Class<*>?): Ctor {
103→            @Suppress("UNCHECKED_CAST")
104→            return createConstructor(type as Class<out Throwable>)
105→        }
106→    }
107→
108→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
109→}
