package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

/**
 * Test for verifying that nested exceptions are handled correctly
 * when the exception class has multiple constructors.
 */
class StackTraceRecoveryNestedExceptionTest : TestBase() {

    /**
     * Exception with constructors in the "problematic" order:
     * String constructor before Throwable constructor
     */
    class NestedException : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    @Test
    fun testNestedExceptionWithStringConstructorFirst() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    /**
     * Exception with constructors in the "working" order:
     * Throwable constructor before String constructor
     */
    class NestedExceptionReversed : RuntimeException {
        constructor(cause: Throwable) : super(cause)
        constructor(message: String) : super(message)
        constructor() : super()
    }

    @Test
    fun testNestedExceptionWithThrowableConstructorFirst() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionReversed(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionReversed, "Expected NestedExceptionReversed but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    /**
     * Exception with both String+Throwable and individual constructors
     */
    class ComplexException : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor(message: String, cause: Throwable) : super(message, cause)
        constructor() : super()
    }

    @Test
    fun testComplexExceptionPrefersTwoArgConstructor() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw ComplexException("Test message", IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ComplexException, "Expected ComplexException but got ${ex::class}")
        assertEquals("Test message", ex.message)
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testComplexExceptionWithOnlyCause() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw ComplexException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is ComplexException, "Expected ComplexException but got ${ex::class}")
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException but got ${ex.cause?.javaClass}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    /**
     * Test with deeply nested exceptions
     */
    @Test
    fun testDeeplyNestedExceptions() = runTest {
        val deepCause = IllegalStateException("ROOT")
        val middleException = NestedException(deepCause)

        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(middleException)
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex::class}")
        assertTrue(ex.cause is NestedException, "Expected first cause to be NestedException but got ${ex.cause?.javaClass}")
        assertTrue((ex.cause as NestedException).cause is IllegalStateException, 
            "Expected second cause to be IllegalStateException but got ${(ex.cause as NestedException).cause?.javaClass}")
        assertEquals("ROOT", ((ex.cause as NestedException).cause as IllegalStateException).message)
    }
}
"}

