/**
 * Direct reproducer test from the GitHub issue report about nested exceptions.
 * This test verifies that the fix for constructor selection works correctly.
 */
class StackTraceRecoveryBugReproducerTest : TestBase() {

    @Test
    fun testNestedException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException)
        // The recovered exception has the original as its cause
        val originalException = ex.cause as? NestedException 
            ?: error("Expected cause to be NestedException but got ${ex.cause?.javaClass}")
        assertTrue(originalException.cause is IllegalStateException)
        assertEquals("ERROR", (originalException.cause as IllegalStateException).message)
    }

    class NestedException : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }
}
